mapper.select:
SELECT DISTINCT uor.role_id
FROM sys_user_org_role uor
INNER JOIN sys_role r
    ON r.id = uor.role_id
   AND r.tenant_id = uor.tenant_id
   AND r.del_flag = 0
WHERE uor.tenant_id = #{tenantId}
  AND uor.user_id = #{userId}
  AND uor.org_id = #{orgId}
ORDER BY uor.role_id ASC

SELECT DISTINCT r.role_name
FROM sys_user_org_role uor
INNER JOIN sys_role r
    ON r.id = uor.role_id
   AND r.tenant_id = uor.tenant_id
   AND r.del_flag = 0
WHERE uor.tenant_id = #{tenantId}
  AND uor.user_id = #{userId}
  AND uor.org_id = #{orgId}
ORDER BY r.sort ASC, r.role_name ASC
